   315→          })}
   316→        </div>
   317→      )}
   318→    </div>
   319→  );
   320→}
   321→
   322→/**
   323→ * Generate human-readable summary of validation rule
   324→ */
   325→function getValidationSummary(validation: DependentValidation, triggerFieldLabel: string): string {
   326→  const { type, condition, validationRule } = validation;
   327→
   328→  const operatorText = getOperatorLabel(condition.operator);
   329→  const valueText =
   330→    condition.operator === 'is_answered' || condition.operator === 'is_not_answered'
   331→      ? ''
   332→      : ` "${condition.value}"`;
   333→
   334→  const validationType =
   335→    type === 'require_if'
   336→      ? 'Required'
   337→      : type === 'min_if'
   338→      ? `Min value: ${validationRule.value}`
   339→      : type === 'max_if'
   340→      ? `Max value: ${validationRule.value}`
   341→      : `Pattern: ${validationRule.value}`;
   342→
   343→  return `${validationType} when ${triggerFieldLabel} ${operatorText}${valueText}`;
   344→}
   345→
   346→/**
   347→ * Get human-readable operator label
   348→ */
   349→function getOperatorLabel(operator: ConditionalOperator): string {
   350→  switch (operator) {
   351→    case 'equals':
   352→      return 'equals';
   353→    case 'not_equals':
   354→      return 'does not equal';
   355→    case 'contains':
   356→      return 'contains';
   357→    case 'greater_than':
   358→      return 'is greater than';
   359→    case 'less_than':
   360→      return 'is less than';
   361→    case 'is_answered':
   362→      return 'is answered';
   363→    case 'is_not_answered':
   364→      return 'is not answered';
   365→    default:
   366→      return operator;
   367→  }
   368→}
