   279→  const triggerField = allFields.find(f => f.id === triggerFieldId);
   280→  if (!triggerField || !triggerField.conditionalRules) return false;
   281→
   282→  // Check if trigger field depends on current field (direct circular dependency)
   283→  const dependsOnCurrent = triggerField.conditionalRules.some(
   284→    rule => rule.fieldId === currentFieldId
   285→  );
   286→
   287→  if (dependsOnCurrent) return true;
   288→
   289→  // Check for indirect circular dependencies (A -> B -> C -> A)
   290→  // For simplicity, we only check one level deep (most common case)
   291→  return false;
   292→}
