/**
 * Quiz Settings Editor Component
 * Configure correct answers, points, and feedback for quiz mode
 */

import type { FormField, QuizSettings } from '../../types/forms';

interface QuizSettingsEditorProps {
  field: FormField;
  onSettingsChange: (settings: QuizSettings | undefined) => void;
}

export function QuizSettingsEditor({ field, onSettingsChange }: QuizSettingsEditorProps) {
  const quizSettings = field.quizSettings;

  const handleChange = (updates: Partial<QuizSettings>) => {
    if (!quizSettings) {
      // Initialize quiz settings
      onSettingsChange({
        correctAnswer: '',
        points: 1,
        ...updates,
      });
    } else {
      onSettingsChange({
        ...quizSettings,
        ...updates,
      });
    }
  };

  const handleRemove = () => {
    onSettingsChange(undefined);
  };

  // Don't show quiz settings for certain field types
  if (field.type === 'calculation' || field.type === 'hidden' || field.type === 'file') {
    return null;
  }

  return (
    <div className="space-y-4 p-4 border border-border-light dark:border-border-dark rounded-lg bg-surface-light-elevated dark:bg-surface-dark-elevated">
      <div className="flex items-center justify-between">
        <h4 className="text-sm font-medium text-text-light-primary dark:text-text-dark-primary">
          Quiz Settings
        </h4>
        {quizSettings && (
          <button
            type="button"
            onClick={handleRemove}
            className="text-xs text-red-500 hover:underline"
          >
            Remove Quiz Settings
          </button>
        )}
      </div>

      {!quizSettings ? (
        <button
          type="button"
          onClick={() => handleChange({})}
          className="w-full px-4 py-2 bg-primary-light dark:bg-primary-dark text-white rounded-lg hover:opacity-90"
        >
          Enable Quiz Mode for This Field
        </button>
      ) : (
        <>
          {/* Correct Answer */}
          <div>
            <label className="block text-sm font-medium text-text-light-primary dark:text-text-dark-primary mb-1">
              Correct Answer *
            </label>

            {/* Text-based fields */}
            {(field.type === 'text' || field.type === 'textarea' || field.type === 'number') && (
              <input
                type={field.type === 'number' ? 'number' : 'text'}
                value={String(quizSettings.correctAnswer || '')}
                onChange={(e) => handleChange({ correctAnswer: field.type === 'number' ? Number(e.target.value) : e.target.value })}
                placeholder="Enter the correct answer"
                className="w-full px-3 py-2 bg-background-light dark:bg-background-dark border border-border-light dark:border-border-dark rounded-lg focus:outline-none focus:ring-2 focus:ring-primary-light dark:focus:ring-primary-dark"
                required
              />
            )}

            {/* Select/Radio fields */}
            {(field.type === 'select' || field.type === 'radio') && (
              <select
                value={String(quizSettings.correctAnswer || '')}
                onChange={(e) => handleChange({ correctAnswer: e.target.value })}
                className="w-full px-3 py-2 bg-background-light dark:bg-background-dark border border-border-light dark:border-border-dark rounded-lg focus:outline-none focus:ring-2 focus:ring-primary-light dark:focus:ring-primary-dark"
                required
              >
                <option value="">Select correct answer</option>
                {field.options?.map((option) => (
                  <option key={option} value={option}>
                    {option}
                  </option>
                ))}
              </select>
            )}

            {/* Multiselect */}
            {field.type === 'multiselect' && (
              <div className="space-y-2">
                {field.options?.map((option) => (
                  <label key={option} className="flex items-center gap-2">
                    <input
                      type="checkbox"
                      checked={Array.isArray(quizSettings.correctAnswer) && quizSettings.correctAnswer.includes(option)}
                      onChange={(e) => {
                        const currentAnswers = Array.isArray(quizSettings.correctAnswer) ? quizSettings.correctAnswer : [];
                        const newAnswers = e.target.checked
                          ? [...currentAnswers, option]
                          : currentAnswers.filter((a) => a !== option);
                        handleChange({ correctAnswer: newAnswers });
                      }}
                      className="w-4 h-4"
                    />
                    <span className="text-sm text-text-light-primary dark:text-text-dark-primary">
                      {option}
                    </span>
                  </label>
                ))}
              </div>
            )}

            {/* Checkbox */}
            {field.type === 'checkbox' && (
              <select
                value={String(quizSettings.correctAnswer || 'false')}
                onChange={(e) => handleChange({ correctAnswer: e.target.value === 'true' })}
                className="w-full px-3 py-2 bg-background-light dark:bg-background-dark border border-border-light dark:border-border-dark rounded-lg focus:outline-none focus:ring-2 focus:ring-primary-light dark:focus:ring-primary-dark"
              >
                <option value="true">Checked (true)</option>
                <option value="false">Unchecked (false)</option>
              </select>
            )}

            {/* Rating/Scale */}
            {(field.type === 'rating' || field.type === 'scale') && (
              <input
                type="number"
                value={Number(quizSettings.correctAnswer || 1)}
                onChange={(e) => handleChange({ correctAnswer: Number(e.target.value) })}
                min={1}
                max={field.type === 'rating' ? 5 : 10}
                placeholder={`Enter correct ${field.type} (${field.type === 'rating' ? '1-5' : '1-10'})`}
                className="w-full px-3 py-2 bg-background-light dark:bg-background-dark border border-border-light dark:border-border-dark rounded-lg focus:outline-none focus:ring-2 focus:ring-primary-light dark:focus:ring-primary-dark"
                required
              />
            )}

            {/* Date/Time fields */}
            {field.type === 'date' && (
              <input
                type="date"
                value={String(quizSettings.correctAnswer || '')}
                onChange={(e) => handleChange({ correctAnswer: e.target.value })}
                className="w-full px-3 py-2 bg-background-light dark:bg-background-dark border border-border-light dark:border-border-dark rounded-lg focus:outline-none focus:ring-2 focus:ring-primary-light dark:focus:ring-primary-dark"
                required
              />
            )}

            {field.type === 'time' && (
              <input
                type="time"
                value={String(quizSettings.correctAnswer || '')}
                onChange={(e) => handleChange({ correctAnswer: e.target.value })}
                className="w-full px-3 py-2 bg-background-light dark:bg-background-dark border border-border-light dark:border-border-dark rounded-lg focus:outline-none focus:ring-2 focus:ring-primary-light dark:focus:ring-primary-dark"
                required
              />
            )}
          </div>

          {/* Points */}
          <div>
            <label className="block text-sm font-medium text-text-light-primary dark:text-text-dark-primary mb-1">
              Points *
            </label>
            <input
              type="number"
              value={quizSettings.points || 1}
              onChange={(e) => handleChange({ points: Number(e.target.value) || 1 })}
              min={1}
              placeholder="Points for this question"
              className="w-full px-3 py-2 bg-background-light dark:bg-background-dark border border-border-light dark:border-border-dark rounded-lg focus:outline-none focus:ring-2 focus:ring-primary-light dark:focus:ring-primary-dark"
              required
            />
          </div>

          {/* Feedback (Optional) */}
          <div>
            <label className="block text-sm font-medium text-text-light-primary dark:text-text-dark-primary mb-1">
              Feedback Message (Optional)
            </label>
            <textarea
              value={quizSettings.feedback || ''}
              onChange={(e) => handleChange({ feedback: e.target.value })}
              placeholder="Optional feedback shown after submission (e.g., 'The capital of France is Paris!')"
              rows={2}
              className="w-full px-3 py-2 bg-background-light dark:bg-background-dark border border-border-light dark:border-border-dark rounded-lg focus:outline-none focus:ring-2 focus:ring-primary-light dark:focus:ring-primary-dark"
            />
          </div>
        </>
      )}
    </div>
  );
}

/**
 * OnboardingModal Component
 *
 * First-time user onboarding experience
 * - Step 1: Welcome screen with product intro and privacy statement
 * - Step 2: Features tour (Notes, Tasks, Calendar, Time Tracking)
 * - Step 3: Setup (display name, default folder, backup reminder)
 * - Step 4: Completion with CTA to create first note/task
 */

import { useState } from 'react';
import { Modal } from './Modal';
import { SupportModal } from './SupportModal';
import { useSettingsStore } from '../stores/useSettingsStore';
import { useThemeStore } from '../stores/useThemeStore';
import { isFileSystemAccessSupported } from '../services/brainBackup';
import { BackupOnboardingModal } from './BackupOnboardingModal';
import {
  FileText,
  CheckSquare,
  Calendar,
  Clock,
  Shield,
  ArrowRight,
  ArrowLeft,
  X,
  Info,
  Wifi,
  Database,
  LayoutDashboard,
  Zap,
  Heart,
  HelpCircle
} from 'lucide-react';

interface OnboardingModalProps {
  isOpen: boolean;
  onClose: () => void;
}

export function OnboardingModal({ isOpen, onClose }: OnboardingModalProps) {
  const [currentStep, setCurrentStep] = useState(1);
  const [displayName, setDisplayName] = useState('');
  const [showSkipOptions, setShowSkipOptions] = useState(false);
  const [selectedReminder, setSelectedReminder] = useState<'in-7-days' | 'monthly' | null>(null);
  const [showBackupModal, setShowBackupModal] = useState(false);
  const [showFaqModal, setShowFaqModal] = useState(false);

  const setOnboardingComplete = useSettingsStore((state) => state.setOnboardingComplete);
  const updateBackupPreferences = useThemeStore((state) => state.updateBackupPreferences);

  const isFSASupported = isFileSystemAccessSupported();

  const totalSteps = 4;

  /**
   * Handle skip tour - mark onboarding complete and close
   */
  const handleSkipTour = () => {
    setOnboardingComplete(true);
    onClose();
  };

  /**
   * Handle completion - save preferences and close
   */
  const handleComplete = () => {
    setOnboardingComplete(true);
    onClose();
  };

  /**
   * Navigate to next step
   */
  const handleNext = () => {
    if (currentStep < totalSteps) {
      setCurrentStep(currentStep + 1);
    }
  };

  /**
   * Navigate to previous step
   */
  const handleBack = () => {
    if (currentStep > 1) {
      setCurrentStep(currentStep - 1);
    }
  };

  /**
   * Open backup setup modal
   */
  const handleSetupBackup = () => {
    setShowBackupModal(true);
  };

  /**
   * Handle backup modal completion
   */
  const handleBackupComplete = () => {
    setShowBackupModal(false);
    handleComplete();
  };

  /**
   * Handle skip with reminder preference
   */
  const handleSkipWithReminder = () => {
    if (selectedReminder) {
      const nextReminderDate =
        selectedReminder === 'in-7-days'
          ? new Date(Date.now() + 7 * 24 * 60 * 60 * 1000).toISOString()
          : new Date(new Date().getFullYear(), new Date().getMonth() + 1, 1).toISOString();

      updateBackupPreferences({
        reminderPreference: selectedReminder,
        nextReminderDate,
      });
    }
    handleComplete();
  };

  /**
   * Handle skip forever (never remind)
   */
  const handleSkipForever = () => {
    updateBackupPreferences({
      reminderPreference: 'never',
      nextReminderDate: null,
    });
    handleComplete();
  };

  /**
   * Step 1: Welcome - Privacy and platform intro
   */
  const renderWelcomeStep = () => (
    <div className="space-y-4">
      {/* Tagline */}
      <p className="text-center text-lg text-text-light-secondary dark:text-text-dark-secondary italic">
        Your Brain. Your Data. Your Device.
      </p>

      {/* Core principles */}
      <div className="bg-surface-light dark:bg-surface-dark border border-border-light dark:border-border-dark rounded-lg p-5 space-y-4">
        <div className="flex items-start gap-3">
          <Shield className="h-6 w-6 text-accent-cyan shrink-0 mt-0.5" />
          <div>
            <h3 className="font-semibold text-text-light-primary dark:text-text-dark-primary mb-1">
              100% Local-First
            </h3>
            <p className="text-sm text-text-light-secondary dark:text-text-dark-secondary">
              All your data stays on your device. No accounts, no servers, no tracking.
              Your information never leaves your computer unless you choose to export it.
            </p>
          </div>
        </div>

        <div className="flex items-start gap-3">
          <Database className="h-6 w-6 text-accent-magenta shrink-0 mt-0.5" />
          <div>
            <h3 className="font-semibold text-text-light-primary dark:text-text-dark-primary mb-1">
              You Own Your Data
            </h3>
            <p className="text-sm text-text-light-secondary dark:text-text-dark-secondary">
              Export everything anytime. No subscriptions, no vendor lock-in.
              Full data portability is built in from day one.
            </p>
          </div>
        </div>

        <div className="flex items-start gap-3">
          <Wifi className="h-6 w-6 text-accent-blue shrink-0 mt-0.5" />
          <div>
            <h3 className="font-semibold text-text-light-primary dark:text-text-dark-primary mb-1">
              Works Offline
            </h3>
            <p className="text-sm text-text-light-secondary dark:text-text-dark-secondary">
              No internet required. Your productivity tools work anywhere, anytime.
              Perfect for focused work without distractions.
            </p>
          </div>
        </div>
      </div>
    </div>
  );

  /**
   * Step 2: Features Tour - What's included
   */
  const renderFeaturesTourStep = () => (
    <div className="space-y-4">
      {/* Core features grid */}
      <div className="grid grid-cols-1 md:grid-cols-2 gap-3">
        <div className="bg-surface-light dark:bg-surface-dark border border-border-light dark:border-border-dark rounded-lg p-4">
          <div className="flex items-center gap-2 mb-2">
            <FileText className="h-5 w-5 text-accent-magenta" />
            <h3 className="font-semibold text-text-light-primary dark:text-text-dark-primary">
              Notes
            </h3>
          </div>
          <p className="text-sm text-text-light-secondary dark:text-text-dark-secondary">
            Rich text editor with folders, tags, slash commands, and full-text search
          </p>
        </div>

        <div className="bg-surface-light dark:bg-surface-dark border border-border-light dark:border-border-dark rounded-lg p-4">
          <div className="flex items-center gap-2 mb-2">
            <CheckSquare className="h-5 w-5 text-accent-cyan" />
            <h3 className="font-semibold text-text-light-primary dark:text-text-dark-primary">
              Tasks
            </h3>
          </div>
          <p className="text-sm text-text-light-secondary dark:text-text-dark-secondary">
            Kanban boards with subtasks, dependencies, priorities, and due dates
          </p>
        </div>

        <div className="bg-surface-light dark:bg-surface-dark border border-border-light dark:border-border-dark rounded-lg p-4">
          <div className="flex items-center gap-2 mb-2">
            <Calendar className="h-5 w-5 text-accent-blue" />
            <h3 className="font-semibold text-text-light-primary dark:text-text-dark-primary">
              Calendar
            </h3>
          </div>
          <p className="text-sm text-text-light-secondary dark:text-text-dark-secondary">
            Month, week, day views with recurring events and ICS import/export
          </p>
        </div>

        <div className="bg-surface-light dark:bg-surface-dark border border-border-light dark:border-border-dark rounded-lg p-4">
          <div className="flex items-center gap-2 mb-2">
            <Clock className="h-5 w-5 text-accent-magenta" />
            <h3 className="font-semibold text-text-light-primary dark:text-text-dark-primary">
              Time Tracking
            </h3>
          </div>
          <p className="text-sm text-text-light-secondary dark:text-text-dark-secondary">
            Timer with projects, daily/weekly stats, reports, and CSV export
          </p>
        </div>
      </div>

      {/* Additional features */}
      <div className="bg-surface-light dark:bg-surface-dark border border-border-light dark:border-border-dark rounded-lg p-4">
        <div className="flex items-center gap-2 mb-3">
          <LayoutDashboard className="h-5 w-5 text-accent-cyan" />
          <h3 className="font-semibold text-text-light-primary dark:text-text-dark-primary">
            44+ Dashboard Widgets
          </h3>
        </div>
        <p className="text-sm text-text-light-secondary dark:text-text-dark-secondary">
          Weather, news, calculator, world clock, pomodoro timer, and more.
          Drag-and-drop to customize your perfect workspace.
        </p>
      </div>
    </div>
  );

  /**
   * Step 3: Setup - Personalization options
   */
  const renderSetupStep = () => (
    <div className="space-y-4">
      {/* Display name input */}
      <div className="bg-surface-light dark:bg-surface-dark border border-border-light dark:border-border-dark rounded-lg p-4">
        <label
          htmlFor="display-name"
          className="block text-sm font-medium text-text-light-primary dark:text-text-dark-primary mb-2"
        >
          Display Name (Optional)
        </label>
        <input
          id="display-name"
          type="text"
          value={displayName}
          onChange={(e) => setDisplayName(e.target.value)}
          placeholder="Enter your name"
          className="w-full px-3 py-2 bg-background-light dark:bg-background-dark border border-border-light dark:border-border-dark rounded-lg text-text-light-primary dark:text-text-dark-primary placeholder:text-text-light-disabled dark:placeholder:text-text-dark-disabled focus:outline-none focus:ring-2 focus:ring-accent-cyan"
        />
        <p className="mt-2 text-xs text-text-light-secondary dark:text-text-dark-secondary">
          This is just for you - stored locally and never shared
        </p>
      </div>

      {/* Backup info */}
      <div className="bg-surface-light dark:bg-surface-dark border border-border-light dark:border-border-dark rounded-lg p-4">
        <div className="flex items-start gap-3">
          <Shield className="h-5 w-5 text-accent-cyan shrink-0 mt-0.5" />
          <div className="flex-1">
            <h3 className="font-semibold text-text-light-primary dark:text-text-dark-primary mb-1">
              Keep Your Data Safe
            </h3>
            <p className="text-sm text-text-light-secondary dark:text-text-dark-secondary mb-2">
              Your data is stored in your browser. Regular backups ensure you never lose your work.
            </p>
            <p className="text-xs text-text-light-secondary dark:text-text-dark-secondary">
              Set up automatic backups anytime in Settings → Backup & Sync
            </p>
          </div>
        </div>
      </div>

      {/* Quick tips */}
      <div className="bg-surface-light dark:bg-surface-dark border border-border-light dark:border-border-dark rounded-lg p-4">
        <div className="flex items-start gap-3">
          <Zap className="h-5 w-5 text-accent-magenta shrink-0 mt-0.5" />
          <div className="flex-1">
            <h3 className="font-semibold text-text-light-primary dark:text-text-dark-primary mb-1">
              Quick Tip
            </h3>
            <p className="text-sm text-text-light-secondary dark:text-text-dark-secondary">
              Press <kbd className="px-1.5 py-0.5 bg-background-light dark:bg-background-dark border border-border-light dark:border-border-dark rounded text-xs font-mono">F1</kbd> for help anytime. Use <kbd className="px-1.5 py-0.5 bg-background-light dark:bg-background-dark border border-border-light dark:border-border-dark rounded text-xs font-mono">Ctrl</kbd> + <kbd className="px-1.5 py-0.5 bg-background-light dark:bg-background-dark border border-border-light dark:border-border-dark rounded text-xs font-mono">B</kbd> to toggle the sidebar.
            </p>
          </div>
        </div>
      </div>
    </div>
  );

  /**
   * Step 4: Completion - Ready to start
   */
  const renderCompletionStep = () => (
    <div className="space-y-4">
      {/* Backup Section - Only show if FSA supported */}
      {isFSASupported && (
        <div className="bg-surface-light dark:bg-surface-dark border border-border-light dark:border-border-dark rounded-lg p-4">
          <div className="flex items-start gap-3 mb-4">
            <Shield className="h-6 w-6 text-accent-cyan shrink-0 mt-0.5" />
            <div>
              <h3 className="font-semibold text-text-light-primary dark:text-text-dark-primary mb-1">
                Enable Auto-Save Backups
              </h3>
              <p className="text-sm text-text-light-secondary dark:text-text-dark-secondary">
                Auto-save to a cloud folder (Dropbox, Google Drive, etc.) for seamless backups.
              </p>
            </div>
          </div>

          <button
            onClick={handleSetupBackup}
            className="w-full flex items-center justify-center gap-2 px-4 py-3 bg-accent-cyan text-white rounded-lg hover:bg-accent-cyan-hover transition-colors font-medium"
          >
            <Shield className="h-4 w-4" />
            <span>Setup Auto-Save Now</span>
          </button>

          {/* Skip Options */}
          {!showSkipOptions ? (
            <button
              onClick={() => setShowSkipOptions(true)}
              className="w-full mt-2 text-sm text-text-light-secondary dark:text-text-dark-secondary hover:text-text-light-primary dark:hover:text-text-dark-primary transition-colors"
            >
              Maybe later...
            </button>
          ) : (
            <div className="mt-3 pt-3 border-t border-border-light dark:border-border-dark">
              <p className="text-xs text-text-light-secondary dark:text-text-dark-secondary mb-2">
                When should we remind you?
              </p>
              <div className="flex gap-2">
                {[
                  { id: 'in-7-days' as const, label: 'In 7 days' },
                  { id: 'monthly' as const, label: 'Monthly' },
                ].map((option) => (
                  <button
                    key={option.id}
                    onClick={() => setSelectedReminder(option.id)}
                    className={`flex-1 p-2 text-center text-sm rounded border transition-all ${
                      selectedReminder === option.id
                        ? 'border-accent-cyan bg-accent-cyan/10 text-text-light-primary dark:text-text-dark-primary'
                        : 'border-border-light dark:border-border-dark hover:border-accent-cyan/50'
                    }`}
                  >
                    {option.label}
                  </button>
                ))}
              </div>
              <div className="flex gap-2 mt-3">
                <button
                  onClick={handleSkipWithReminder}
                  disabled={!selectedReminder}
                  className="flex-1 px-3 py-2 bg-accent-magenta text-white rounded text-sm font-medium disabled:opacity-50 disabled:cursor-not-allowed"
                >
                  Confirm
                </button>
                <button
                  onClick={handleSkipForever}
                  className="px-3 py-2 text-sm text-text-light-secondary dark:text-text-dark-secondary hover:text-status-error transition-colors"
                >
                  Never remind
                </button>
              </div>
            </div>
          )}
        </div>
      )}

      {/* Non-FSA Browser Message */}
      {!isFSASupported && (
        <div className="bg-status-info/10 border border-status-info rounded-lg p-4">
          <div className="flex items-start gap-3">
            <Info className="h-5 w-5 text-status-info shrink-0 mt-0.5" />
            <p className="text-sm text-text-light-primary dark:text-text-dark-primary">
              <strong>Note:</strong> Auto-save requires Chrome, Edge, or Brave.
              You can manually export your data anytime from Settings.
            </p>
          </div>
        </div>
      )}

      {/* Get Started Section */}
      <div className="bg-surface-light dark:bg-surface-dark border border-border-light dark:border-border-dark rounded-lg p-5">
        <h3 className="font-semibold text-text-light-primary dark:text-text-dark-primary text-center mb-4">
          Ready to Get Started?
        </h3>

        <div className="grid grid-cols-1 md:grid-cols-2 gap-3">
          <button
            onClick={handleComplete}
            className="flex items-center justify-center gap-2 px-4 py-3 bg-accent-magenta text-white rounded-lg hover:bg-accent-magenta-hover transition-colors"
          >
            <FileText className="h-4 w-4" />
            <span className="font-medium">Create Your First Note</span>
          </button>

          <button
            onClick={handleComplete}
            className="flex items-center justify-center gap-2 px-4 py-3 bg-accent-cyan text-white rounded-lg hover:bg-accent-cyan-hover transition-colors"
          >
            <CheckSquare className="h-4 w-4" />
            <span className="font-medium">Create Your First Task</span>
          </button>
        </div>

        <p className="text-xs text-center text-text-light-secondary dark:text-text-dark-secondary mt-4">
          All features are accessible from the sidebar
        </p>
      </div>

      {/* Built with care message */}
      <div className="text-center pt-2">
        <p className="text-xs text-text-light-secondary dark:text-text-dark-secondary flex items-center justify-center gap-1">
          <Heart className="h-3 w-3 text-accent-magenta" />
          Built with care for privacy, productivity, and open source
        </p>
      </div>

      {/* Backup Modal (inline) */}
      <BackupOnboardingModal
        isOpen={showBackupModal}
        onClose={handleBackupComplete}
      />
    </div>
  );

  /**
   * Render current step content
   */
  const renderStepContent = () => {
    switch (currentStep) {
      case 1:
        return renderWelcomeStep();
      case 2:
        return renderFeaturesTourStep();
      case 3:
        return renderSetupStep();
      case 4:
        return renderCompletionStep();
      default:
        return null;
    }
  };

  /**
   * Get step-specific subtitle text
   */
  const getStepSubtitle = () => {
    switch (currentStep) {
      case 1:
        return 'Your privacy-first productivity platform';
      case 2:
        return 'Everything you need to stay organized';
      case 3:
        return 'Personalize your experience';
      case 4:
        return "You're all set!";
      default:
        return '';
    }
  };

  return (
    <Modal isOpen={isOpen} onClose={onClose} title="Welcome to Neuman Brain" maxWidth="lg" hideHeader>
      <div className="flex flex-col">
        {/* Persistent Header: Logo + Title + Subtitle + Progress + Close */}
        <div className="flex-shrink-0 pb-4 border-b border-border-light dark:border-border-dark">
          {/* Close button - top right */}
          <div className="flex justify-end mb-2">
            <button
              onClick={handleSkipTour}
              className="p-1 text-text-light-secondary dark:text-text-dark-secondary hover:text-text-light-primary dark:hover:text-text-dark-primary transition-colors"
              aria-label="Close"
            >
              <X className="h-5 w-5" />
            </button>
          </div>

          {/* Logo + Title + Subtitle */}
          <div className="text-center mb-4">
            <img
              src="/images/logos/nb3.png"
              alt="Neuman Brain"
              className="w-16 h-16 mx-auto mb-3 rounded-lg"
            />
            <h2 className="text-2xl font-bold text-text-light-primary dark:text-text-dark-primary">
              Welcome to Neuman Brain
            </h2>
            <p className="text-text-light-secondary dark:text-text-dark-secondary mt-1">
              {getStepSubtitle()}
            </p>
          </div>

          {/* Progress indicator - with visible border in both modes */}
          <div className="flex items-center justify-center gap-2">
            {Array.from({ length: totalSteps }).map((_, index) => (
              <div
                key={index}
                className={`h-2 w-10 rounded-full transition-colors border border-border-light dark:border-border-dark ${
                  index + 1 === currentStep
                    ? 'bg-accent-magenta'
                    : index + 1 < currentStep
                    ? 'bg-accent-cyan'
                    : 'bg-gray-200 dark:bg-gray-700'
                }`}
              />
            ))}
          </div>
        </div>

        {/* Step Content - fixed height for consistent modal size (sized to fit page 4) */}
        <div className="py-5 min-h-[480px]">
          {renderStepContent()}
        </div>

        {/* Navigation Footer - fixed 3-column layout: Back/FAQ | Skip | Next */}
        <div className="flex-shrink-0 grid grid-cols-3 items-center pt-4 border-t border-border-light dark:border-border-dark">
          {/* Left column: FAQ button on step 1, Back button on other steps */}
          <div className="justify-self-start">
            {currentStep === 1 ? (
              <button
                onClick={() => setShowFaqModal(true)}
                className="flex items-center gap-2 px-4 py-2 text-text-light-secondary dark:text-text-dark-secondary hover:text-text-light-primary dark:hover:text-text-dark-primary transition-colors"
              >
                <HelpCircle className="h-4 w-4" />
                <span>FAQ</span>
              </button>
            ) : (
              <button
                onClick={handleBack}
                className="flex items-center gap-2 px-4 py-2 text-text-light-secondary dark:text-text-dark-secondary hover:text-text-light-primary dark:hover:text-text-dark-primary transition-colors"
              >
                <ArrowLeft className="h-4 w-4" />
                <span>Back</span>
              </button>
            )}
          </div>

          {/* Skip tour - always centered */}
          <div className="justify-self-center">
            <button
              onClick={handleSkipTour}
              className="text-sm text-text-light-secondary dark:text-text-dark-secondary hover:text-text-light-primary dark:hover:text-text-dark-primary transition-colors"
            >
              Skip tour
            </button>
          </div>

          {/* Next button - always present, changes to "Done" on last step */}
          <div className="justify-self-end">
            <button
              onClick={currentStep < totalSteps ? handleNext : handleComplete}
              className="flex items-center gap-2 px-6 py-2 bg-accent-magenta text-white rounded-lg hover:bg-accent-magenta-hover transition-colors"
            >
              <span>{currentStep < totalSteps ? 'Next' : 'Done'}</span>
              <ArrowRight className="h-4 w-4" />
            </button>
          </div>
        </div>
      </div>

      {/* FAQ Modal - opens to Help tab with FAQs */}
      <SupportModal
        isOpen={showFaqModal}
        onClose={() => setShowFaqModal(false)}
        initialTab="help"
      />
    </Modal>
  );
}

