   121→        </label>
   122→        <select
   123→          value={category}
   124→          onChange={(e) => setCategory(e.target.value as 'Work' | 'Personal' | 'Productivity')}
   125→          className="w-full px-3 py-2 bg-surface-light dark:bg-surface-dark border border-border-light dark:border-border-dark rounded-lg text-text-light-primary dark:text-text-dark-primary focus:outline-none focus:ring-2 focus:ring-accent-blue"
   126→        >
   127→          <option value="Work">Work</option>
   128→          <option value="Personal">Personal</option>
   129→          <option value="Productivity">Productivity</option>
   130→        </select>
   131→      </div>
   132→
   133→      {/* Description Textarea */}
   134→      <div>
   135→        <label className="block text-sm font-medium text-text-light-primary dark:text-text-dark-primary mb-2">
   136→          Template Content *
   137→        </label>
   138→        <textarea
   139→          value={description}
   140→          onChange={(e) => setDescription(e.target.value)}
   141→          placeholder="Enter template content here..."
   142→          rows={10}
   143→          className="w-full px-3 py-2 bg-surface-light dark:bg-surface-dark border border-border-light dark:border-border-dark rounded-lg text-text-light-primary dark:text-text-dark-primary focus:outline-none focus:ring-2 focus:ring-accent-blue font-mono text-sm resize-y"
   144→        />
   145→        {errors.description && <p className="text-sm text-red-500 mt-1">{errors.description}</p>}
   146→        <div className="mt-2 p-3 bg-surface-light-elevated dark:bg-surface-dark-elevated rounded-lg border border-border-light dark:border-border-dark">
   147→          <p className="text-xs font-medium text-text-light-secondary dark:text-text-dark-secondary mb-2">
   148→            Available template variables:
   149→          </p>
   150→          <div className="grid grid-cols-2 gap-2 text-xs text-text-light-secondary dark:text-text-dark-secondary">
   151→            <div>
   152→              <code className="px-1.5 py-0.5 bg-accent-purple/10 text-accent-purple rounded">
   153→                {'{date}'}
   154→              </code>{' '}
   155→              Current date
   156→            </div>
   157→            <div>
   158→              <code className="px-1.5 py-0.5 bg-accent-purple/10 text-accent-purple rounded">
   159→                {'{time}'}
   160→              </code>{' '}
   161→              Current time
   162→            </div>
   163→            <div>
   164→              <code className="px-1.5 py-0.5 bg-accent-purple/10 text-accent-purple rounded">
   165→                {'{datetime}'}
   166→              </code>{' '}
   167→              Date and time
   168→            </div>
   169→            <div>
   170→              <code className="px-1.5 py-0.5 bg-accent-purple/10 text-accent-purple rounded">
   171→                {'{title}'}
   172→              </code>{' '}
   173→              Note title
   174→            </div>
   175→            <div>
   176→              <code className="px-1.5 py-0.5 bg-accent-purple/10 text-accent-purple rounded">
   177→                {'{user}'}
   178→              </code>{' '}
   179→              User name
   180→            </div>
   181→            <div>
   182→              <code className="px-1.5 py-0.5 bg-accent-purple/10 text-accent-purple rounded">
   183→                {'{timestamp}'}
   184→              </code>{' '}
   185→              Unix timestamp
   186→            </div>
   187→          </div>
   188→        </div>
   189→      </div>
   190→
   191→      {/* Default Tags */}
   192→      <div>
   193→        <label className="block text-sm font-medium text-text-light-primary dark:text-text-dark-primary mb-2">
   194→          Default Tags
   195→        </label>
   196→        <div className="flex gap-2 mb-2">
   197→          <input
   198→            type="text"
   199→            value={tagInput}
   200→            onChange={(e) => setTagInput(e.target.value)}
   201→            onKeyDown={(e) => {
   202→              if (e.key === 'Enter') {
   203→                e.preventDefault();
   204→                handleAddTag();
   205→              }
   206→            }}
   207→            placeholder="Add a tag..."
   208→            className="flex-1 px-3 py-2 bg-surface-light dark:bg-surface-dark border border-border-light dark:border-border-dark rounded-lg text-text-light-primary dark:text-text-dark-primary focus:outline-none focus:ring-2 focus:ring-accent-blue"
   209→          />
   210→          <button
   211→            type="button"
   212→            onClick={handleAddTag}
