   263→/**
   264→ * Template Card Component
   265→ */
   266→interface TemplateCardProps {
   267→  template: NoteTemplate;
   268→  onSelect?: () => void;
   269→  onEdit?: () => void;
   270→  onDelete?: () => void;
   271→}
   272→
   273→function TemplateCard({ template, onSelect, onEdit, onDelete }: TemplateCardProps) {
   274→  const canEdit = !template.isBuiltIn;
   275→
   276→  return (
   277→    <div className="group relative bg-surface-light dark:bg-surface-dark border border-border-light dark:border-border-dark rounded-lg p-4 hover:border-accent-cyan dark:hover:border-accent-magenta hover:shadow-md transition-all">
   278→      {/* Built-in Badge */}
   279→      {template.isBuiltIn && (
   280→        <div className="absolute top-2 right-2 px-2 py-0.5 bg-accent-blue/10 text-accent-blue text-xs font-medium rounded">
   281→          Built-in
   282→        </div>
   283→      )}
   284→
   285→      {/* Icon */}
   286→      <div className="flex items-start gap-3 mb-3">
   287→        <div className="w-10 h-10 flex items-center justify-center bg-surface-light-elevated dark:bg-surface-dark-elevated rounded-lg text-xl">
