   312→            >
   313→              <TagIcon className="w-3 h-3" />
   314→              {tag}
   315→            </span>
   316→          ))}
   317→          {template.defaultTags.length > 3 && (
   318→            <span className="text-xs text-text-light-tertiary dark:text-text-dark-tertiary px-1">
