   359→/**
   360→ * Template Library Modal Component
   361→ */
   362→export function TemplateLibrary({ isOpen, onClose, onSelect }: TemplateLibraryProps) {
   363→  const getAllNoteTemplates = useNotesStore((state) => state.getAllNoteTemplates);
   364→  const createNoteTemplate = useNotesStore((state) => state.createNoteTemplate);
   365→  const updateNoteTemplate = useNotesStore((state) => state.updateNoteTemplate);
   366→  const deleteNoteTemplate = useNotesStore((state) => state.deleteNoteTemplate);
   367→
   368→  const [selectedCategory, setSelectedCategory] = useState<TemplateCategory>('All');
   369→  const [searchQuery, setSearchQuery] = useState('');
   370→  const [showForm, setShowForm] = useState(false);
   371→  const [editingTemplate, setEditingTemplate] = useState<NoteTemplate | undefined>(undefined);
   372→  const [deleteConfirmTemplate, setDeleteConfirmTemplate] = useState<NoteTemplate | null>(null);
   373→
   374→  // Get all templates
   375→  const allTemplates = getAllNoteTemplates();
   376→
   377→  // Filter templates
   378→  const filteredTemplates = useMemo(() => {
   379→    let filtered = allTemplates;
   380→
   381→    // Filter by category
   382→    if (selectedCategory !== 'All') {
   383→      filtered = filtered.filter((t) => t.category === selectedCategory);
   384→    }
   385→
   386→    // Filter by search query
   387→    if (searchQuery.trim()) {
   388→      const query = searchQuery.toLowerCase();
   389→      filtered = filtered.filter(
   390→        (t) =>
   391→          t.name.toLowerCase().includes(query) ||
   392→          t.description.toLowerCase().includes(query) ||
   393→          (t.defaultTags && t.defaultTags.some((tag) => tag.toLowerCase().includes(query)))
   394→      );
   395→    }
   396→
   397→    return filtered;
   398→  }, [allTemplates, selectedCategory, searchQuery]);
   399→
   400→  const handleCreateTemplate = () => {
   401→    setEditingTemplate(undefined);
   402→    setShowForm(true);
   403→  };
   404→
   405→  const handleEditTemplate = (template: NoteTemplate) => {
   406→    setEditingTemplate(template);
   407→    setShowForm(true);
   408→  };
   409→
   410→  const handleSaveTemplate = (data: Partial<NoteTemplate>) => {
   411→    if (editingTemplate) {
   412→      updateNoteTemplate(editingTemplate.id, data);
   413→    } else {
   414→      createNoteTemplate(data);
   415→    }
   416→    setShowForm(false);
   417→    setEditingTemplate(undefined);
   418→  };
   419→
   420→  const handleDeleteTemplate = (template: NoteTemplate) => {
   421→    setDeleteConfirmTemplate(template);
   422→  };
   423→
   424→  const confirmDelete = () => {
   425→    if (deleteConfirmTemplate) {
   426→      deleteNoteTemplate(deleteConfirmTemplate.id);
   427→      setDeleteConfirmTemplate(null);
   428→    }
   429→  };
   430→
   431→  const handleSelectTemplate = (template: NoteTemplate) => {
   432→    if (onSelect) {
   433→      onSelect(template);
   434→    }
   435→    onClose();
   436→  };
   437→
   438→  if (!isOpen) return null;
   439→
   440→  return (
   441→    <div className="fixed inset-0 z-[9999] flex items-center justify-center p-4 bg-black/50">
   442→      {/* Backdrop */}
   443→      <div className="absolute inset-0" onClick={onClose} />
   444→
   445→      {/* Modal */}
   446→      <div className="relative bg-surface-light dark:bg-surface-dark rounded-lg shadow-modal border border-border-light dark:border-border-dark w-full max-w-6xl max-h-[90vh] flex flex-col">
   447→        {/* Header */}
   448→        <div className="flex items-center justify-between px-6 py-4 border-b border-border-light dark:border-border-dark flex-shrink-0">
   449→          <h2 className="text-2xl font-bold text-text-light-primary dark:text-text-dark-primary">
   450→            {showForm ? (editingTemplate ? 'Edit Template' : 'Create Template') : 'Template Library'}
   451→          </h2>
   452→          <button
   453→            onClick={onClose}
   454→            className="p-2 text-text-light-secondary dark:text-text-dark-secondary hover:text-text-light-primary dark:hover:text-text-dark-primary transition-colors"
   455→            aria-label="Close modal"
   456→          >
   457→            <X className="w-5 h-5" />
   458→          </button>
   459→        </div>
   460→
   461→        {/* Content */}
   462→        <div className="flex-1 overflow-y-auto p-6">
   463→          {showForm ? (
   464→            /* Template Form */
   465→            <TemplateForm
   466→              template={editingTemplate}
   467→              onSave={handleSaveTemplate}
   468→              onCancel={() => {
   469→                setShowForm(false);
   470→                setEditingTemplate(undefined);
   471→              }}
   472→            />
   473→          ) : (
   474→            /* Template Gallery */
   475→            <>
   476→              {/* Controls */}
   477→              <div className="mb-6 space-y-4">
   478→                {/* Search */}
   479→                <div className="relative">
   480→                  <Search className="absolute left-3 top-1/2 -translate-y-1/2 w-5 h-5 text-text-light-secondary dark:text-text-dark-secondary" />
   481→                  <input
   482→                    type="text"
   483→                    placeholder="Search templates by name, description, or tags..."
   484→                    value={searchQuery}
   485→                    onChange={(e) => setSearchQuery(e.target.value)}
   486→                    className="w-full pl-10 pr-4 py-2 bg-surface-light-elevated dark:bg-surface-dark-elevated border border-border-light dark:border-border-dark rounded-lg text-text-light-primary dark:text-text-dark-primary focus:outline-none focus:ring-2 focus:ring-accent-blue"
   487→                  />
   488→                </div>
   489→
   490→                {/* Category Filter + New Button */}
   491→                <div className="flex items-center justify-between gap-4">
   492→                  <div className="flex gap-2 overflow-x-auto">
   493→                    {(['All', 'Work', 'Personal', 'Productivity'] as TemplateCategory[]).map((cat) => (
   494→                      <button
   495→                        key={cat}
   496→                        onClick={() => setSelectedCategory(cat)}
   497→                        className={`flex items-center gap-2 px-4 py-2 rounded-lg text-sm font-medium whitespace-nowrap transition-colors ${
   498→                          selectedCategory === cat
   499→                            ? 'bg-accent-cyan dark:bg-accent-magenta text-white'
   500→                            : 'bg-surface-light-elevated dark:bg-surface-dark-elevated text-text-light-primary dark:text-text-dark-primary hover:bg-border-light dark:hover:bg-border-dark'
   501→                        }`}
   502→                      >
   503→                        <span>{categoryIcons[cat]}</span>
   504→                        {cat}
   505→                      </button>
   506→                    ))}
   507→                  </div>
   508→                  <button
   509→                    onClick={handleCreateTemplate}
   510→                    className="flex items-center gap-2 px-4 py-2 bg-accent-blue text-white rounded-lg hover:bg-accent-blue-hover transition-colors flex-shrink-0"
   511→                  >
   512→                    <Plus className="w-4 h-4" />
   513→                    New Template
   514→                  </button>
   515→                </div>
   516→              </div>
   517→
   518→              {/* Template Grid */}
   519→              {filteredTemplates.length === 0 ? (
   520→                <div className="text-center py-12">
   521→                  <p className="text-text-light-secondary dark:text-text-dark-secondary">
   522→                    {searchQuery.trim()
   523→                      ? `No templates found matching "${searchQuery}"`
   524→                      : selectedCategory !== 'All'
   525→                      ? `No templates in ${selectedCategory} category`
   526→                      : 'No templates available'}
   527→                  </p>
   528→                  {!searchQuery.trim() && selectedCategory === 'All' && (
   529→                    <button
   530→                      onClick={handleCreateTemplate}
   531→                      className="mt-4 px-6 py-3 bg-accent-blue text-white rounded-lg hover:bg-accent-blue-hover transition-colors inline-flex items-center gap-2"
   532→                    >
   533→                      <Plus className="w-5 h-5" />
   534→                      Create Your First Template
   535→                    </button>
   536→                  )}
   537→                </div>
   538→              ) : (
   539→                <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
   540→                  {filteredTemplates.map((template) => (
   541→                    <TemplateCard
   542→                      key={template.id}
   543→                      template={template}
   544→                      onSelect={onSelect ? () => handleSelectTemplate(template) : undefined}
   545→                      onEdit={!template.isBuiltIn ? () => handleEditTemplate(template) : undefined}
   546→                      onDelete={!template.isBuiltIn ? () => handleDeleteTemplate(template) : undefined}
   547→                    />
   548→                  ))}
   549→                </div>
   550→              )}
   551→            </>
   552→          )}
   553→        </div>
   554→      </div>
   555→
   556→      {/* Delete Confirmation Dialog */}
   557→      {deleteConfirmTemplate && (
   558→        <ConfirmDialog
   559→          isOpen={true}
   560→          onClose={() => setDeleteConfirmTemplate(null)}
   561→          onConfirm={confirmDelete}
   562→          title="Delete Template"
   563→          message={`Are you sure you want to delete the template "${deleteConfirmTemplate.name}"? This action cannot be undone.`}
   564→          confirmText="Delete"
   565→          variant="danger"
   566→        />
   567→      )}
   568→    </div>
   569→  );
   570→}
