                    </span>
                  </label>
                ))}
              </div>
            )}

            {/* Checkbox */}
            {field.type === 'checkbox' && (
              <select
                value={String(quizSettings.correctAnswer || 'false')}
                onChange={(e) => handleChange({ correctAnswer: e.target.value === 'true' })}
                className="w-full px-3 py-2 bg-background-light dark:bg-background-dark border border-border-light dark:border-border-dark rounded-lg focus:outline-none focus:ring-2 focus:ring-accent-magenta"
              >
                <option value="true">Checked (true)</option>
