            <input
              type="number"
              value={quizSettings.points || 1}
              onChange={(e) => handleChange({ points: Number(e.target.value) || 1 })}
              min={1}
              placeholder="Points for this question"
              className="w-full px-3 py-2 bg-background-light dark:bg-background-dark border border-border-light dark:border-border-dark rounded-lg focus:outline-none focus:ring-2 focus:ring-accent-magenta"
              required
            />
          </div>

          {/* Feedback (Optional) */}
          <div>
            <label className="block text-sm font-medium text-text-light-primary dark:text-text-dark-primary mb-1">
              Feedback Message (Optional)
            </label>
            <textarea
              value={quizSettings.feedback || ''}
